INSERT INTO question_display_rules (id, question_id, expected_option_id, next_question_id, transition_text, display_order, is_active) VALUES (1, 1, 1, 2, 'That’s a strong starting point. Since the customer perspective is already present in most discussions, is there also a shared plan to keep improving the experience?', 1, TRUE);
INSERT INTO question_display_rules (id, question_id, expected_option_id, next_question_id, transition_text, display_order, is_active) VALUES (2, 1, 2, 2, 'That helps. So the customer perspective is part of some conversations, but not all of them yet. Is there a clear plan to strengthen it?', 2, TRUE);
INSERT INTO question_display_rules (id, question_id, expected_option_id, next_question_id, transition_text, display_order, is_active) VALUES (3, 1, 3, 2, 'Thanks, that gives a good picture. If the customer perspective mostly comes up when something goes wrong, is there a plan to work on the experience more proactively?', 3, TRUE);
INSERT INTO question_display_rules (id, question_id, expected_option_id, next_question_id, transition_text, display_order, is_active) VALUES (4, 1, 4, 2, 'I see. If the customer perspective rarely comes up today, is there at least a plan in place to improve the experience?', 4, TRUE);
INSERT INTO question_display_rules (id, question_id, expected_option_id, next_question_id, transition_text, display_order, is_active) VALUES (5, 2, 5, 3, 'That’s a good foundation. With a plan already in place, who usually takes the lead on these topics?', 5, TRUE);
INSERT INTO question_display_rules (id, question_id, expected_option_id, next_question_id, transition_text, display_order, is_active) VALUES (6, 2, 6, 3, 'Got it. So the plan exists, but it has not reached everyone yet. Who usually takes the lead on these topics today?', 6, TRUE);
INSERT INTO question_display_rules (id, question_id, expected_option_id, next_question_id, transition_text, display_order, is_active) VALUES (7, 2, 7, 3, 'That makes sense. If there are ideas on the table but no shared plan yet, who usually pulls these topics forward?', 7, TRUE);
INSERT INTO question_display_rules (id, question_id, expected_option_id, next_question_id, transition_text, display_order, is_active) VALUES (8, 2, 8, 3, 'Thanks, that’s helpful to know. Without a clear plan today, who usually takes the lead on customer experience topics?', 8, TRUE);
INSERT INTO question_display_rules (id, question_id, expected_option_id, next_question_id, transition_text, display_order, is_active) VALUES (9, 3, 9, 4, 'That’s useful. With one clear owner in place, how do people across the organization learn what a good customer experience looks like here?', 9, TRUE);
INSERT INTO question_display_rules (id, question_id, expected_option_id, next_question_id, transition_text, display_order, is_active) VALUES (10, 3, 10, 4, 'That helps. Since a few teams share the role, how do people usually learn what good customer experience looks like here?', 10, TRUE);
INSERT INTO question_display_rules (id, question_id, expected_option_id, next_question_id, transition_text, display_order, is_active) VALUES (11, 3, 11, 4, 'Understood. If ownership shifts depending on the topic, how do people usually learn what good customer experience looks like?', 11, TRUE);
INSERT INTO question_display_rules (id, question_id, expected_option_id, next_question_id, transition_text, display_order, is_active) VALUES (12, 3, 12, 4, 'I see. If ownership is not very clear today, how do people learn what good customer experience looks like in practice?', 12, TRUE);
INSERT INTO question_display_rules (id, question_id, expected_option_id, next_question_id, transition_text, display_order, is_active) VALUES (13, 5, 17, 6, 'That is a strong starting point. You are hearing from customers at the moments that matter most. Once that feedback comes in, what usually happens next?', 13, TRUE);
INSERT INTO question_display_rules (id, question_id, expected_option_id, next_question_id, transition_text, display_order, is_active) VALUES (14, 5, 18, 6, 'That helps. So there is already a regular rhythm in place. Once feedback comes in, what do you usually do with it?', 14, TRUE);
INSERT INTO question_display_rules (id, question_id, expected_option_id, next_question_id, transition_text, display_order, is_active) VALUES (15, 5, 19, 6, 'Got it. So feedback is gathered at certain moments, but not all the time. When it does come in, what usually happens next?', 15, TRUE);
INSERT INTO question_display_rules (id, question_id, expected_option_id, next_question_id, transition_text, display_order, is_active) VALUES (16, 5, 20, 6, 'That makes sense. So feedback mostly appears when something needs attention. When that happens, what do you usually do next?', 16, TRUE);
INSERT INTO question_display_rules (id, question_id, expected_option_id, next_question_id, transition_text, display_order, is_active) VALUES (17, 5, 21, 6, 'Thanks, that is helpful to know. If customer input comes in through complaints, teams, or day-to-day interactions, what usually happens with it?', 17, TRUE);
INSERT INTO question_display_rules (id, question_id, expected_option_id, next_question_id, transition_text, display_order, is_active) VALUES (18, 6, 22, 7, 'That is a solid base. It means feedback is already feeding decisions. When you look across the experience, what journeys or moments do you actually track today?', 18, TRUE);
INSERT INTO question_display_rules (id, question_id, expected_option_id, next_question_id, transition_text, display_order, is_active) VALUES (19, 6, 23, 7, 'That is a useful start. So there is already some structure in how feedback is handled. What journeys or moments do you tend to track today?', 19, TRUE);
INSERT INTO question_display_rules (id, question_id, expected_option_id, next_question_id, transition_text, display_order, is_active) VALUES (20, 6, 24, 7, 'I see. So the picture is built one issue at a time today. What journeys or moments do you usually keep an eye on?', 20, TRUE);
INSERT INTO question_display_rules (id, question_id, expected_option_id, next_question_id, transition_text, display_order, is_active) VALUES (21, 6, 25, 7, 'Understood. So the challenge is not only hearing customers, but making use of what is heard. What journeys or moments do you track today, if any?', 21, TRUE);
INSERT INTO question_display_rules (id, question_id, expected_option_id, next_question_id, transition_text, display_order, is_active) VALUES (22, 7, 26, 8, 'That gives you quite a complete view. How often do you go back and refresh that journey view?', 22, TRUE);
INSERT INTO question_display_rules (id, question_id, expected_option_id, next_question_id, transition_text, display_order, is_active) VALUES (23, 7, 27, 8, 'That makes sense. Focusing on the key journeys first is often a practical way to start. How often do you revisit that view?', 23, TRUE);
INSERT INTO question_display_rules (id, question_id, expected_option_id, next_question_id, transition_text, display_order, is_active) VALUES (24, 7, 28, 8, 'Got it. So the view is still centered on specific touchpoints more than the full journey. How often is that view updated?', 24, TRUE);
INSERT INTO question_display_rules (id, question_id, expected_option_id, next_question_id, transition_text, display_order, is_active) VALUES (25, 7, 29, 8, 'Understood. So you mostly see the experience through the moments where things go wrong. How often do you step back and update that view?', 25, TRUE);
INSERT INTO question_display_rules (id, question_id, expected_option_id, next_question_id, transition_text, display_order, is_active) VALUES (26, 7, 30, 8, 'Thanks, that gives a clear picture. If there is any journey view today, how often does it actually get reviewed or updated?', 26, TRUE);
INSERT INTO question_display_rules (id, question_id, expected_option_id, next_question_id, transition_text, display_order, is_active) VALUES (27, 8, 31, 9, 'That is a positive sign. It suggests the journey view stays alive over time. When you decide where to focus, how do you decide which journeys or moments matter most?', 27, TRUE);
INSERT INTO question_display_rules (id, question_id, expected_option_id, next_question_id, transition_text, display_order, is_active) VALUES (28, 8, 32, 9, 'That helps. So the journey view gets refreshed from time to time. When you decide where to focus, how do you usually make that choice?', 28, TRUE);
INSERT INTO question_display_rules (id, question_id, expected_option_id, next_question_id, transition_text, display_order, is_active) VALUES (29, 8, 33, 9, 'Got it. So updates happen, but not very often. In that context, how do you decide which journeys or moments deserve attention first?', 29, TRUE);
INSERT INTO question_display_rules (id, question_id, expected_option_id, next_question_id, transition_text, display_order, is_active) VALUES (30, 8, 34, 9, 'I see. So keeping focus on the right moments becomes even more important. How do you usually decide what matters most?', 30, TRUE);
INSERT INTO question_display_rules (id, question_id, expected_option_id, next_question_id, transition_text, display_order, is_active) VALUES (31, 10, 39, 11, 'That’s a positive sign. When action happens quickly, how do you usually tell whether the change really made a difference?', 31, TRUE);
INSERT INTO question_display_rules (id, question_id, expected_option_id, next_question_id, transition_text, display_order, is_active) VALUES (32, 10, 40, 11, 'That helps. So issues are usually picked up. Once something is changed, how do you normally tell whether it really helped?', 32, TRUE);
